import { getAppBootstrapData } from "./app-bootstrap";
import { listCampaigns } from "./campaigns";

export type DashboardCampaign = {
  id: number;
  name: string;
};

export type DashboardPageData = {
  campaigns: DashboardCampaign[];
  cards: {
    campaigns: number;
    payouts: number;
    transactions: number;
  };
};

export async function getDashboardPageData(): Promise<DashboardPageData | null> {
  const bootstrap = await getAppBootstrapData();
  if (!bootstrap?.currentTenant) {
    return null;
  }

  const campaigns = (await listCampaigns()) ?? [];
  const simplified = campaigns.map((c) => ({ id: c.id, name: c.name }));

  return {
    campaigns: simplified,
    cards: {
      campaigns: simplified.length,
      payouts: 7,
      transactions: 428,
    },
  };
}

