    expect(orgApiScopedPath("/campaigns", { tenantId: 42 })).toBe(
      "/campaigns?tenant_id=42",
    );
  });

  it("adds tenant_id and vendor_id when vendor scope is present", () => {
    expect(
      orgApiScopedPath("/campaigns", { tenantId: 42, vendorId: 7 }),
    ).toBe("/campaigns?tenant_id=42&vendor_id=7");
  });

  it("encodes member paths", () => {
    expect(orgApiScopedPath("/campaigns/101", { tenantId: 1 })).toBe(
      "/campaigns/101?tenant_id=1",
    );
  });
});

