import { useEffect, useState } from "react";
import { createFileRoute, Link, useRouter } from "@tanstack/react-router";
import {
  Button,
  Card,
  Heading,
  Input,
  Paragraph,
  Separator,
} from "@workspace/ui";
import { ArrowLeft, Loader2 } from "lucide-react";
import { AppHeader } from "../../../components/app-header";
import { Field, FieldLabel } from "../../../components/ui/field";
import {
  getCampaignDetailPageDataFn,
  updateCampaignFn,
} from "../../../server/campaigns.functions";

export const Route = createFileRoute("/_authed/campaigns/$campaignId")({
  loader: ({ params }) =>
    getCampaignDetailPageDataFn({ data: { campaignId: params.campaignId } }),
  component: CampaignDetailPage,
});

function formatDateTime(iso: string) {
  try {
    return new Date(iso).toLocaleString();
  } catch {
    return iso;
  }
}

function CampaignDetailPage() {
  const { campaignId } = Route.useParams();
  const { campaign } = Route.useLoaderData();
  const router = useRouter();
  const [isEditing, setIsEditing] = useState(false);
  const [editedName, setEditedName] = useState(campaign.name);
  const [isSaving, setIsSaving] = useState(false);
  const [saveError, setSaveError] = useState<string | null>(null);

  useEffect(() => {
    if (!isEditing) {
      setEditedName(campaign.name);
    }
  }, [campaign.id, campaign.name, isEditing]);

  const handleSave = async () => {
    const trimmed = editedName.trim();
    if (!trimmed) return;

    setSaveError(null);
    setIsSaving(true);
    try {
      await updateCampaignFn({
        data: { campaignId, name: trimmed },
      });
      await router.invalidate();
      setIsEditing(false);
    } catch {
      setSaveError("Could not save changes. Try again.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleCancelEdit = () => {
    setEditedName(campaign.name);
    setSaveError(null);
    setIsEditing(false);
  };

  return (
    <div className="min-h-screen bg-muted font-outfit">
      <AppHeader />

      <main className="mx-auto max-w-2xl px-6 py-8">
        <Link
          to="/"
          className="mb-6 inline-flex items-center gap-1.5 font-medium text-muted-foreground text-sm transition-colors hover:text-foreground"
        >
          <ArrowLeft size={14} />
          Back to dashboard
        </Link>

        <Heading
          as="h1"
          variant="h3"
          className="mb-6 font-bold text-foreground"
        >
          {campaign.name}
        </Heading>

        <Card className="p-6">
          <Heading
            as="h2"
            variant="h5"
            className="mb-4 font-semibold text-foreground"
          >
            Campaign details
          </Heading>
          <dl className="space-y-3 text-sm">
            <div>
              <dt className="font-medium text-muted-foreground">ID</dt>
              <dd className="mt-0.5 text-foreground">{campaign.id}</dd>
            </div>
            <div>
              <dt className="font-medium text-muted-foreground">Name</dt>
              <dd className="mt-0.5 text-foreground">{campaign.name}</dd>
            </div>
            <div>
              <dt className="font-medium text-muted-foreground">Created</dt>
              <dd className="mt-0.5 text-foreground">
                {formatDateTime(campaign.created_at)}
              </dd>
            </div>
            <div>
              <dt className="font-medium text-muted-foreground">Updated</dt>
              <dd className="mt-0.5 text-foreground">
                {formatDateTime(campaign.updated_at)}
              </dd>
            </div>
          </dl>

          <Separator className="my-6" />

          <Heading
            as="h2"
            variant="h5"
            className="mb-3 font-semibold text-foreground"
          >
            Edit name
          </Heading>

          {!isEditing ? (
            <Button
              type="button"
              variant="outline"
              size="sm"
              onClick={() => {
                setEditedName(campaign.name);
                setIsEditing(true);
              }}
            >
              Edit campaign name
            </Button>
          ) : (
            <div className="flex flex-col gap-4">
              <Field>
                <FieldLabel htmlFor="campaign-name-edit">Name</FieldLabel>
                <Input
                  id="campaign-name-edit"
                  value={editedName}
                  onChange={(e) => setEditedName(e.target.value)}
                  className="max-w-md"
                />
              </Field>
              {saveError ? (
                <Paragraph className="text-destructive text-sm">
                  {saveError}
                </Paragraph>
              ) : null}
              <div className="flex gap-2">
                <Button
                  type="button"
                  disabled={isSaving || editedName.trim().length === 0}
                  onClick={handleSave}
                >
                  {isSaving && <Loader2 className="animate-spin" size={16} />}
                  {isSaving ? "Saving…" : "Save"}
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  disabled={isSaving}
                  onClick={handleCancelEdit}
                >
                  Cancel
                </Button>
              </div>
            </div>
          )}
        </Card>
      </main>
    </div>
  );
}

