import { beforeEach, describe, expect, it, vi } from "vitest";
import type { AppBootstrap } from "@/types/bootstrap";
import type { Tenant } from "@/types/bootstrap";
import { OrgApiError } from "./error";

const orgTenant = {
  id: 42,
  tenant_type: "org" as const,
  name: "Hope",
  org_id: "org-42",
  vendor_id: null,
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
} satisfies Tenant;

const vendorTenant = {
  id: 43,
  tenant_type: "vendor" as const,
  name: "Vendor",
  org_id: null,
  vendor_id: "ven-43",
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
} satisfies Tenant;

function bootstrapWithTenant(tenant: Tenant): AppBootstrap {
  return {
    accessibleTenants: [tenant],
    currentTenant: tenant,
    currentUser: {
      id: 1,
      email: "u@example.com",
      cognito_sub: null,
      created_at: "2024-01-01T00:00:00Z",
      updated_at: "2024-01-01T00:00:00Z",
    },
    tenant,
    tenants: [tenant],
    user: {
      id: 1,
      email: "u@example.com",
      cognito_sub: null,
      created_at: "2024-01-01T00:00:00Z",
      updated_at: "2024-01-01T00:00:00Z",
    },
    users: [],
  };
}

const mocks = vi.hoisted(() => ({
  getAppBootstrapData: vi.fn(),
  getOrgApiJson: vi.fn(),
  postOrgApiJson: vi.fn(),
  putOrgApiJson: vi.fn(),
}));

vi.mock("./app-bootstrap", () => ({
  getAppBootstrapData: mocks.getAppBootstrapData,
}));

vi.mock("./org-api.server", () => ({
  getOrgApiJson: mocks.getOrgApiJson,
  postOrgApiJson: mocks.postOrgApiJson,
  putOrgApiJson: mocks.putOrgApiJson,
}));

describe("campaigns server module", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("does not POST when current tenant is vendor (org-only create)", async () => {
    mocks.getAppBootstrapData.mockResolvedValue(bootstrapWithTenant(vendorTenant));

    const { createCampaignForCurrentTenant } = await import("./campaigns");

    await expect(createCampaignForCurrentTenant("X")).rejects.toThrow(
      OrgApiError,
    );
    await expect(createCampaignForCurrentTenant("X")).rejects.toMatchObject({
      status: 403,
    });

    expect(mocks.postOrgApiJson).not.toHaveBeenCalled();
  });

  it("POST /campaigns with scoped path and CampaignCreate body for org tenant", async () => {
    mocks.getAppBootstrapData.mockResolvedValue(bootstrapWithTenant(orgTenant));
    const created = {
      id: 99,
      name: "Alpha",
      created_at: "2024-01-02T00:00:00Z",
      updated_at: "2024-01-02T00:00:00Z",
    };
    mocks.postOrgApiJson.mockResolvedValue(created);

    const { createCampaignForCurrentTenant } = await import("./campaigns");

    const result = await createCampaignForCurrentTenant("Alpha");

    expect(result).toEqual(created);
    expect(mocks.postOrgApiJson).toHaveBeenCalledTimes(1);
    expect(mocks.postOrgApiJson).toHaveBeenCalledWith(
      "/campaigns?tenant_id=42",
      { campaign: { name: "Alpha" } },
    );
  });

  it("PUT /campaigns/:id with scoped path and CampaignUpdate body", async () => {
    mocks.getAppBootstrapData.mockResolvedValue(bootstrapWithTenant(orgTenant));
    const updated = {
      id: 5,
      name: "Renamed",
      created_at: "2024-01-01T00:00:00Z",
      updated_at: "2024-01-03T00:00:00Z",
    };
    mocks.putOrgApiJson.mockResolvedValue(updated);

    const { updateCampaign } = await import("./campaigns");

    const result = await updateCampaign("5", { name: "Renamed" });

    expect(result).toEqual(updated);
    expect(mocks.putOrgApiJson).toHaveBeenCalledTimes(1);
    expect(mocks.putOrgApiJson).toHaveBeenCalledWith(
      "/campaigns/5?tenant_id=42",
      { campaign: { name: "Renamed" } },
    );
  });

  it("GET /campaigns with tenant scope for list", async () => {
    mocks.getAppBootstrapData.mockResolvedValue(bootstrapWithTenant(orgTenant));
    mocks.getOrgApiJson.mockResolvedValue([]);

    const { listCampaigns } = await import("./campaigns");

    await listCampaigns();

    expect(mocks.getOrgApiJson).toHaveBeenCalledWith("/campaigns?tenant_id=42");
  });
});

