import { useState } from "react";
import type { SubmitEvent } from "react";
import {
  createFileRoute,
  redirect,
  useNavigate,
  useRouter,
} from "@tanstack/react-router";
import { Button, Card, Input } from "@workspace/ui";
import { Loader2, X } from "lucide-react";
import { Field, FieldLabel } from "../../../components/ui/field";
import { getAppBootstrapData } from "../../../server/app-bootstrap";
import { createCampaignFn } from "../../../server/campaigns.functions";

export const Route = createFileRoute("/_authed/campaigns/new")({
  loader: async () => {
    const bootstrap = await getAppBootstrapData();
    if (bootstrap?.currentTenant?.tenant_type === "vendor") {
      throw redirect({ to: "/" });
    }
    return null;
  },
  component: CampaignCreatePage,
});

function CampaignCreatePage() {
  const navigate = useNavigate();
  const router = useRouter();
  const [isCreating, setIsCreating] = useState(false);

  const handleSubmit = async (event: SubmitEvent<HTMLFormElement>) => {
    event.preventDefault();
    const formData = new FormData(event.currentTarget);
    const rawName = formData.get("campaignName");
    const trimmedName = typeof rawName === "string" ? rawName.trim() : "";
    if (!trimmedName) {
      return;
    }

    setIsCreating(true);
    try {
      const campaign = await createCampaignFn({
        data: { name: trimmedName },
      });

      await router.invalidate();

      navigate({
        to: "/campaigns/$campaignId",
        params: { campaignId: campaign.id.toString() },
      });
    } finally {
      setIsCreating(false);
    }
  };

  const handleClose = () => {
    navigate({ to: "/" });
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-foreground/40 p-6 font-outfit backdrop-blur-sm">
      <Card className="w-full max-w-md overflow-hidden shadow-2xl">
        <div className="flex items-center justify-between p-6 pb-0">
          <h2 className="font-bold text-foreground text-lg">Create campaign</h2>
          <Button
            type="button"
            onClick={handleClose}
            variant="ghost"
            size="icon-sm"
            aria-label="Close create campaign"
            className="text-muted-foreground hover:text-foreground"
          >
            <X size={16} />
          </Button>
        </div>

        <form onSubmit={handleSubmit}>
          <div className="flex flex-col gap-5 p-6">
            <Field>
              <FieldLabel htmlFor="campaign-name">Campaign name</FieldLabel>
              <Input
                id="campaign-name"
                name="campaignName"
                required
                minLength={1}
                placeholder="e.g. Spring Gala 2026"
                className="h-10"
                autoComplete="off"
              />
            </Field>
          </div>

          <div className="flex justify-end gap-2.5 border-border border-t p-4">
            <Button type="button" variant="outline" onClick={handleClose}>
              Cancel
            </Button>
            <Button type="submit" disabled={isCreating}>
              {isCreating && <Loader2 className="animate-spin" size={16} />}
              {isCreating ? "Creating..." : "Create campaign"}
            </Button>
          </div>
        </form>
      </Card>
    </div>
  );
}

