import Rollbar from "rollbar";

export const isRollbarEnabled =
  import.meta.env.PROD && !!import.meta.env.VITE_ROLLBAR_ACCESS_TOKEN;

const MAX_SERIALIZED_PAYLOAD_LENGTH = 1000;

const serializeResponsePayload = (data: unknown) => {
  if (data == null) {
    return undefined;
  }

  try {
