    if (serialized.length > MAX_SERIALIZED_PAYLOAD_LENGTH) {
      return `${serialized.slice(0, MAX_SERIALIZED_PAYLOAD_LENGTH)}…`;
    }

    return serialized;
  } catch {
    return "[unserializable]";
  }
