export function reportClientError(
  error: unknown,
  context: Record<string, unknown>,
  userMessage: string,
) {
  const err = error instanceof Error ? error : new Error(String(error));
  logErrorToRollbar(err, { ...context, source: "org-next-client" });
  toast.error(userMessage);
}

