import { createRequire } from "node:module";
import { getRequestHeaders } from "@tanstack/start-server-core";
import { bypass, http, HttpResponse } from "msw";
import { type SetupServerApi, setupServer } from "msw/node";
import type { MockSchema } from "request-mocking-protocol";
import { extractMockSchemas } from "request-mocking-protocol/dist/transport/index.js";
import { RMP_MOCK_HEADER } from "./rmpConstants";

const require = createRequire(import.meta.url);

const { matchSchemas } = require(
  "request-mocking-protocol/dist/request-matcher/utils.js",
) as {
  matchSchemas: (
    req: Request,
    mockSchemas?: MockSchema[],
  ) => Promise<
    import("request-mocking-protocol").MockMatchResult | undefined
  >;
};

const { ResponseBuilder } = require(
  "request-mocking-protocol/dist/response-builder/index.js",
) as {
  ResponseBuilder: new (
    matchResult: import("request-mocking-protocol").MockMatchResult,
    callbacks: { bypass: (req: Request) => Promise<Response> },
  ) => { build: () => Promise<unknown> };
};

let mswServer: SetupServerApi | null = null;

function parseMockSchemasFromHeaders(headers: Headers): MockSchema[] | undefined {
  const raw = headers.get(RMP_MOCK_HEADER);
  if (!raw) {
    return;
  }
  try {
    return JSON.parse(raw) as MockSchema[];
  } catch {
    return;
  }
}

export function setupRequestMocking(): SetupServerApi {
  if (mswServer) {
    return mswServer;
  }

  const mockHandler = http.all("*", async ({ request }) => {
    const fromOutgoingRequest = parseMockSchemasFromHeaders(request.headers);
    const fromIncomingHttp = await extractMockSchemas(() =>
      getRequestHeaders(),
    );
    const mockSchemas =
      fromOutgoingRequest && fromOutgoingRequest.length > 0
        ? fromOutgoingRequest
        : fromIncomingHttp;

    if (!mockSchemas?.length) {
      return;
    }

    const matchResult = await matchSchemas(request, mockSchemas);
    if (!matchResult) {
      return;
    }

    const built = await new ResponseBuilder(matchResult, {
      bypass: (req) => fetch(bypass(req)),
    }).build();

    const { body, headers, status, statusText } = built as {
      body: string | ArrayBuffer | null;
      headers: Headers;
      status: number;
      statusText: string;
    };

    return new HttpResponse(body, { status, statusText, headers });
  });

  mswServer = setupServer(
    mockHandler as unknown as Parameters<typeof setupServer>[0],
  );
  mswServer.listen({
    onUnhandledRequest(request) {
      console.error(
        `[MSW] Unhandled request: ${request.method} ${request.url}`,
      );
      throw new Error(
        `[MSW] Unhandled request: ${request.method} ${request.url}`,
      );
    },
  });
  return mswServer;
}

